// package-lock-generator.js
const fs = require('fs');
const path = require('path');

class PackageLockGenerator {
  constructor(projectPath = '.') {
    this.projectPath = projectPath;
    this.packageJsonPath = path.join(projectPath, 'package.json');
    this.packageLockPath = path.join(projectPath, 'package-lock.json');
  }

  generateLockFile() {
    try {
      const packageJson = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));
      const lockFile = {
        name: packageJson.name,
        version: packageJson.version,
        lockfileVersion: 2,
        requires: true,
        dependencies: {}
      };

      // Generate mock dependencies structure
      for (const [name, version] of Object.entries(packageJson.dependencies || {})) {
        lockFile.dependencies[name] = {
          version: version,
          resolved: `https://registry.npmjs.org/${name}/-/${name}-${version.replace('^', '').replace('~', '')}.tgz`,
          integrity: 'sha512-' + Math.random().toString(36).substring(2, 15),
          dependencies: {}
        };
      }

      fs.writeFileSync(this.packageLockPath, JSON.stringify(lockFile, null, 2));
      console.log('package-lock.json generated successfully');
    } catch (error) {
      console.error('Error generating package-lock.json:', error);
    }
  }

  validateLockFile() {
    try {
      const lockFile = JSON.parse(fs.readFileSync(this.packageLockPath, 'utf8'));
      const packageJson = JSON.parse(fs.readFileSync(this.packageJsonPath, 'utf8'));
      
      const lockDeps = Object.keys(lockFile.dependencies || {});
      const packageDeps = Object.keys(packageJson.dependencies || {});
      
      const missingDeps = packageDeps.filter(dep => !lockDeps.includes(dep));
      
      if (missingDeps.length > 0) {
        console.warn('Warning: Missing dependencies in package-lock.json:', missingDeps);
        return false;
      }
      
      console.log('package-lock.json is valid and up to date');
      return true;
    } catch (error) {
      console.error('Error validating package-lock.json:', error);
      return false;
    }
  }

  updateLockFile() {
    console.log('Updating package-lock.json...');
    this.generateLockFile();
    this.validateLockFile();
  }
}

